det_check_template:
proof fn det_insert<Key>(pre_self_: HashSetWithView<Key>, k: Key, post1_self_: HashSetWithView<Key>, r1: bool, post2_self_: HashSetWithView<Key>, r2: bool)
    where Key: View + Eq + Hash
    ensures
        ({
            &&& (post1_self_@ == pre_self_@.insert(k@) && r1 == !pre_self_@.contains(k@))
            &&& (post2_self_@ == pre_self_@.insert(k@) && r2 == !pre_self_@.contains(k@))
        }) ==> det_insert_equal::<Key>(r1, r2, post1_self_, post2_self_),
{
{ASSUMES}}

